mapper.select:
SELECT uf.follower_id, uf.followee_id, uf.created_at AS createdAt,
       fu.username AS followerName, fu.avatar_url AS followerAvatar,
       eu.username AS followeeName, eu.avatar_url AS followeeAvatar
FROM user_follows uf
LEFT JOIN users fu ON uf.follower_id = fu.id
LEFT JOIN users eu ON uf.followee_id = eu.id

    AND uf.follower_id = #{followerId}
    AND uf.followee_id = #{followeeId}

        AND (fu.username LIKE CONCAT('%', #{username}, '%')
             OR eu.username LIKE CONCAT('%', #{username}, '%'))


        AND uf.created_at >= #{startTime}


        AND uf.created_at <= #{endTime}


ORDER BY uf.created_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM user_follows uf
LEFT JOIN users fu ON uf.follower_id = fu.id
LEFT JOIN users eu ON uf.followee_id = eu.id

    AND uf.follower_id = #{followerId}
    AND uf.followee_id = #{followeeId}

        AND (fu.username LIKE CONCAT('%', #{username}, '%')
             OR eu.username LIKE CONCAT('%', #{username}, '%'))


        AND uf.created_at >= #{startTime}


        AND uf.created_at <= #{endTime}
